mapper.insert:
insert into saved_location (
      member_id
    , location_name
    , location_type
    , address
    , latitude
    , longitude
    , location
    , is_default
)
values (
      #{memberId}
    , #{locationName}
    , coalesce(#{locationType}, 'CUSTOM')
    , #{address}
    , #{latitude}
    , #{longitude}
    , ST_SetSRID(ST_MakePoint(#{longitude}, #{latitude}), 4326)::geography
    , coalesce(#{isDefault}, false)
)

mapper.update:
update saved_location
   set is_default = true
     , updated_at = current_timestamp
 where member_id = #{memberId}
   and location_id = #{locationId}

mapper.delete:
delete from saved_location
 where member_id = #{memberId}
   and location_id = #{locationId}
